    for (int i = 0; i < N; i++) {
        if (fork() == 0) {
            arr[i] = i * 10;
            _exit(0);
        }
    }
    for (int i = 0; i < N; i++)
        wait(NULL);

    for (int i = 0; i < N; i++)
        printf("arr[%d]=%d\n", i, arr[i]);

    munmap(arr, N * sizeof(int));
    shm_unlink("/kf_shm_array");
    return 0;
}

