/* == EXEMPLE =======================================
 * 2 enfants ecrivent dans un tableau partage
 * ================================================= */
void example_shm_arr(void) {
    int fd = shm_open("/kf_ex_arr", O_CREAT|O_RDWR, 0644);
    ftruncate(fd, 2*sizeof(int));
    int *a = (int *)mmap(NULL, 2*sizeof(int), PROT_READ|PROT_WRITE, MAP_SHARED, fd, 0);
    close(fd);
    for (int i = 0; i < 2; i++) {
        if (fork() == 0) { a[i] = (i+1)*5; _exit(0); }
    }
    wait(NULL); wait(NULL);
    printf("[%d, %d]\n", a[0], a[1]);
    munmap(a, 2*sizeof(int)); shm_unlink("/kf_ex_arr");
}
